// ═══════════════════════════════════════════════
// GREETING GENERATOR — Time-aware, Language-aware
// ═══════════════════════════════════════════════
const hour = new Date().getHours();
const prevData = $input.first().json;

// ── Parse CRM caller data ──
let callerName = '';
let callerLang = 'en';
try {
  const crmRows = prevData.values || [];
  // Find caller by phone number (Column A = phone)
  for (let i = 1; i < crmRows.length; i++) {
    if (crmRows[i] && crmRows[i][0] === prevData.caller_number) {
      callerName = crmRows[i][1] || '';
      callerLang = crmRows[i][2] || 'en';
      break;
    }
  }
} catch(e) {}

// ── Parse business config ──
let bizConfig = { business_name: 'our venue', timings: '', menu_highlights: '', current_offers: '', vip_options: '', address: '', escalation_number: '' };
try {
  // Business config comes from second input of merge
  // Try to find it in the merged data
  const allItems = $input.all();
  for (const item of allItems) {
    if (item.json && item.json.values) {
      const rows = item.json.values;
      if (rows.length > 1 && rows[0]) {
        const headers = rows[0].map(h => h.toLowerCase().replace(/[\s]+/g, '_'));
        const vals = rows[1] || [];
        headers.forEach((h, i) => {
          if (vals[i]) bizConfig[h] = vals[i];
        });
      }
    }
  }
} catch(e) {}

const businessName = bizConfig.business_name || 'our venue';

// ── Greeting by time + language ──
const greetings = {
  en: { morning: 'Good morning', afternoon: 'Good afternoon', evening: 'Good evening' },
  ta: { morning: 'காலை வணக்கம்', afternoon: 'மதிய வணக்கம்', evening: 'மாலை வணக்கம்' },
  te: { morning: 'శుభోదయం', afternoon: 'శుభ మధ్యాహ్నం', evening: 'శుభ సాయంత్రం' },
  kn: { morning: 'ಶುಭೋದಯ', afternoon: 'ಶುಭ ಮಧ್ಯಾಹ್ನ', evening: 'ಶುಭ ಸಂಜೆ' },
  ml: { morning: 'സുപ്രഭാതം', afternoon: 'ശുഭ ഉച്ചയ്ക്ക്', evening: 'ശുഭ സന്ധ്യ' }
};

let slot = 'morning';
if (hour >= 12 && hour < 17) slot = 'afternoon';
if (hour >= 17) slot = 'evening';

const g = (greetings[callerLang] || greetings.en)[slot];

let message;
if (callerName) {
  message = `${g}! Welcome back ${callerName}! This is ${businessName}. How can I help you today?`;
} else {
  message = `${g}! Thank you for calling ${businessName}. My name is Priya. How may I assist you?`;
}

return [{ json: {
  session_id: prevData.session_id || prevData.body?.CallSid || '',
  caller_number: prevData.caller_number || prevData.body?.From || '',
  business_number: prevData.business_number || prevData.body?.To || '',
  detected_language: callerLang,
  caller_name: callerName,
  emotion_state: 'neutral',
  turn_count: 0,
  silence_count: 0,
  detected_intent: 'unknown',
  needs_escalation: false,
  conversation_history: [],
  collected_data: {},
  business_config: bizConfig,
  greeting_message: message
}}];

// Build TwiML: play greeting, then record caller's response
const s = $input.first().json;
const sid = s.session_id;
const base = $env.N8N_BASE_URL || 'https://your-n8n.com';
const msg = (s.greeting_message || 'Welcome! How can I help you?').replace(/["<>&]/g, '');

// Check if ElevenLabs returned audio binary
const hasBinary = Object.keys($input.first().binary || {}).length > 0;

let playSection;
if (hasBinary) {
  // In production: upload binary to S3/GCS, get URL, use <Play>
  // Fallback to <Say> for now (reliable across all setups)
  playSection = `<Say voice="Polly.Aditi" language="en-IN">${msg}</Say>`;
} else {
  playSection = `<Say voice="Polly.Aditi" language="en-IN">${msg}</Say>`;
}

const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  ${playSection}
  <Record maxLength="15" timeout="3" playBeep="false" transcribe="false"
    action="${base}/webhook/voice-agent/turn?sid=${sid}" />
  <Say voice="Polly.Aditi" language="en-IN">I am still here if you need anything.</Say>
  <Record maxLength="15" timeout="5" playBeep="false" transcribe="false"
    action="${base}/webhook/voice-agent/turn?sid=${sid}" />
</Response>`;

return [{ json: { ...s, twiml_response: twiml } }];

// Extract all relevant fields from Twilio's POST
const raw = $input.first().json;
const body = raw.body || raw;
const query = raw.query || {};

return [{ json: {
  session_id: query.sid || body.CallSid || '',
  caller_number: body.From || '',
  business_number: body.To || '',
  recording_url: body.RecordingUrl || '',
  recording_sid: body.RecordingSid || '',
  call_status: body.CallStatus || '',
  speech_result: body.SpeechResult || '',
  digits: body.Digits || ''
}}];

// ═══ SILENCE HANDLER ═══
// Progressive: prompt → ask → end call with WhatsApp fallback
const s = $input.first().json;
const base = $env.N8N_BASE_URL || 'https://your-n8n.com';
const sid = s.session_id;

// In production, read silence_count from Redis/session store
// For now, treat each silence as first occurrence
const silenceCount = 1;

let msg, shouldEnd = false;
if (silenceCount <= 1) {
  msg = "I didn't quite catch that. Could you please go ahead? I'm listening.";
} else if (silenceCount === 2) {
  msg = "Hello? Are you still there? Take your time, I'm here whenever you're ready.";
} else {
  msg = "It seems like we're having trouble connecting. I'll send you a WhatsApp message so you can reach us easily. Thank you for calling!";
  shouldEnd = true;
}

let twiml;
if (shouldEnd) {
  twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Aditi" language="en-IN">${msg}</Say>
  <Hangup/>
</Response>`;
} else {
  twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Aditi" language="en-IN">${msg}</Say>
  <Record maxLength="15" timeout="3" playBeep="false" transcribe="false"
    action="${base}/webhook/voice-agent/turn?sid=${sid}" />
  <Say voice="Polly.Aditi" language="en-IN">I am still here.</Say>
  <Record maxLength="15" timeout="5" playBeep="false" transcribe="false"
    action="${base}/webhook/voice-agent/turn?sid=${sid}" />
</Response>`;
}

return [{ json: { ...s, twiml_response: twiml, silence_detected: true, should_end: shouldEnd } }];

// ═══ PARSE STT + DETECT LANGUAGE ═══
const input = $input.first().json;
let transcript = '', lang = 'en', confidence = 0;

try {
  const ch = input.results.channels[0];
  const alt = ch.alternatives[0];
  transcript = alt.transcript || '';
  confidence = alt.confidence || 0;
  lang = ch.detected_language || 'en';
} catch(e) { transcript = ''; }

// Normalize lang code
const norm = { 'ta': 'ta','ta-IN':'ta','te':'te','te-IN':'te','kn':'kn','kn-IN':'kn','ml':'ml','ml-IN':'ml','en':'en','en-IN':'en','en-US':'en','hi':'hi','hi-IN':'hi' };
const names = { ta:'Tamil', te:'Telugu', kn:'Kannada', ml:'Malayalam', en:'English', hi:'Hindi' };
const nl = norm[lang] || 'en';

return [{ json: {
  session_id: input.session_id || '',
  caller_number: input.caller_number || '',
  business_number: input.business_number || '',
  recording_url: input.recording_url || '',
  caller_transcript: transcript,
  detected_language: nl,
  language_name: names[nl] || 'English',
  stt_confidence: confidence,
  is_empty: transcript.trim() === ''
}}];

// ═══════════════════════════════════════════
// EMOTION DETECTION ENGINE
// ═══════════════════════════════════════════
const s = $input.first().json;
const text = s.caller_transcript;
const low = text.toLowerCase();

const anger = ['worst','terrible','disgusting','pathetic','waste','cheat','fraud','angry','disappointed','unacceptable','ridiculous','horrible','damn','hell','useless','stupid'];
const urgency = ['urgent','immediately','right now','emergency','asap','hurry','quickly','fast','tonight','today only','need now','running late'];
const confusion = ['confused','don\'t understand','what do you mean','unclear','not sure','which one','huh','sorry what','come again','pardon'];
const happy = ['great','awesome','perfect','wonderful','amazing','excellent','fantastic','love it','thank you so much','brilliant','superb'];
const escalate = ['manager','supervisor','human','real person','transfer','speak to someone','complaint','higher authority','your boss','escalate'];

let emotion = 'neutral', needsEsc = false, conf = 0.5;

if (escalate.some(k => low.includes(k))) { needsEsc = true; emotion = 'wants_escalation'; conf = 0.95; }
else if (anger.some(k => low.includes(k))) { emotion = 'angry'; conf = 0.8; }
else if (urgency.some(k => low.includes(k))) { emotion = 'urgent'; conf = 0.8; }
else if (confusion.some(k => low.includes(k))) { emotion = 'confused'; conf = 0.7; }
else if (happy.some(k => low.includes(k))) { emotion = 'happy'; conf = 0.7; }

const bangs = (text.match(/!/g) || []).length;
if (bangs > 2 && emotion === 'neutral') { emotion = 'frustrated'; conf = 0.65; }

return [{ json: { ...s, emotion_state: emotion, emotion_confidence: conf, needs_escalation: needsEsc } }];

// ═══ TRANSFER TO HUMAN AGENT ═══
const s = $input.first().json;
const escNum = $env.ESCALATION_PHONE || '+919876543210';
const transferMsg = 'I completely understand. Let me connect you with my colleague right away. Please hold for just a moment.';
const fallbackMsg = 'I am sorry, our team member is unavailable right now. We will call you back within 15 minutes. Thank you for your patience.';

const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Aditi" language="en-IN">${transferMsg}</Say>
  <Dial timeout="30" callerId="${s.business_number}">
    <Number>${escNum}</Number>
  </Dial>
  <Say voice="Polly.Aditi" language="en-IN">${fallbackMsg}</Say>
</Response>`;

return [{ json: { ...s, twiml_response: twiml, escalation_triggered: true } }];

// ═══ PARSE AI RESPONSE + EXTRACT STRUCTURED DATA ═══
const input = $input.first().json;
let aiText = '';
try { aiText = input.content[0].text || ''; }
catch(e) { aiText = 'I am sorry, could you repeat that? I missed what you said.'; }

// Extract <data> block
let extracted = {};
const m = aiText.match(/<data>([\s\S]*?)<\/data>/);
if (m) { try { extracted = JSON.parse(m[1]); } catch(e) {} }

// Clean spoken text (remove data block)
const spoken = aiText.replace(/<data>[\s\S]*?<\/data>/g, '').trim();

// Check booking completeness
const d = extracted;
const bookingDone = d.intent === 'booking' && d.date && d.time && d.guests && d.name;

return [{ json: {
  session_id: input.session_id,
  caller_number: input.caller_number,
  business_number: input.business_number,
  detected_language: input.detected_language,
  language_name: input.language_name,
  emotion_state: input.emotion_state,
  caller_transcript: input.caller_transcript,
  ai_response: spoken,
  extracted_data: extracted,
  detected_intent: extracted.intent || 'unknown',
  booking_complete: bookingDone || false
}}];

// ═══════════════════════════════════════════
// HUMANIZATION ENGINE
// Makes AI sound natural and human-like
// ═══════════════════════════════════════════
const s = $input.first().json;
const resp = s.ai_response;
const emo = s.emotion_state;

// ── Filler injection (60% chance) ──
const fills = {
  neutral: ['Sure!','Absolutely.','Of course.','Right.','Got it.'],
  thinking: ['Let me check...','One moment...','Let me see...','Hmm, let me look into that...'],
  empathy: ['I understand.','I hear you.','That makes sense.','I completely get it.']
};

let h = resp;
if (Math.random() < 0.6) {
  let set;
  if (emo === 'angry' || emo === 'frustrated') set = fills.empathy;
  else if (resp.length > 120) set = fills.thinking;
  else set = fills.neutral;
  h = set[Math.floor(Math.random() * set.length)] + ' ' + h;
}

// ── Speed adaptation ──
let rate = '100%';
if (emo === 'urgent') rate = '115%';
if (emo === 'angry' || emo === 'frustrated') rate = '90%';
if (emo === 'confused') rate = '85%';

// ── Response delay (simulates human thinking) ──
const words = resp.split(' ').length;
let delay = Math.min(400 + words * 30, 1500);
if (emo === 'urgent') delay = Math.max(delay - 300, 200);

return [{ json: { ...s, ai_response_humanized: h, speak_rate: rate, response_delay_ms: delay } }];

// ═══ BUILD TWIML — Play response + record next turn ═══
const s = $input.first().json;
const sid = s.session_id;
const base = $env.N8N_BASE_URL || 'https://your-n8n.com';
const endCall = s.should_end_call || false;
const spoken = (s.ai_response || 'Could you repeat that?').replace(/["<>&]/g, c => ({'"':'&quot;','<':'&lt;','>':'&gt;','&':'&amp;'}[c]));

let twiml;
if (endCall) {
  twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Aditi" language="en-IN">${spoken}</Say>
  <Hangup/>
</Response>`;
} else {
  twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Aditi" language="en-IN">${spoken}</Say>
  <Record maxLength="15" timeout="3" playBeep="false" transcribe="false"
    action="${base}/webhook/voice-agent/turn?sid=${sid}" />
  <Say voice="Polly.Aditi" language="en-IN">I am still here if you need anything.</Say>
  <Record maxLength="15" timeout="5" playBeep="false" transcribe="false"
    action="${base}/webhook/voice-agent/turn?sid=${sid}" />
</Response>`;
}

return [{ json: { ...s, twiml_response: twiml } }];

// Log call completion and trigger post-call actions
const body = $input.first().json.body || $input.first().json;
const status = body.CallStatus || 'unknown';
const duration = body.CallDuration || '0';
const sid = body.CallSid || '';

// Determine if this was a dropped call (short duration + no completion)
const wasDropped = (status === 'completed' && parseInt(duration) < 10) ||
  status === 'failed' || status === 'busy' || status === 'no-answer';

return [{ json: {
  session_id: sid,
  call_status: status,
  call_duration: parseInt(duration),
  was_dropped: wasDropped,
  caller_number: body.From || '',
  timestamp: new Date().toISOString()
}}];

const raw = $input.first().json;
const query = raw.query || {};
const body = raw.body || raw;
const name = query.name || 'there';
const purpose = query.purpose || 'follow_up';
const machine = body.AnsweredBy || '';
const base = $env.N8N_BASE_URL || 'https://your-n8n.com';
const sid = body.CallSid || '';

// Voicemail → short message
if (machine.includes('machine')) {
  const vmMsg = `Hi ${name}, this is Priya calling from the venue. We have something special for you. Please call us back at your convenience. Thank you!`;
  const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response><Say voice="Polly.Aditi" language="en-IN">${vmMsg}</Say><Hangup/></Response>`;
  return [{ json: { twiml_response: twiml, is_voicemail: true } }];
}

// Human answered → purpose-specific greeting
const templates = {
  booking_reminder: `Hi ${name}! This is Priya from the venue. I'm calling to confirm your reservation for tomorrow. Do you have a quick moment?`,
  follow_up: `Hello ${name}! This is Priya calling from the venue. We noticed you enquired about our services recently. I just wanted to check if you'd like to go ahead with a booking?`,
  event_promo: `Hi ${name}! This is Priya from the venue. We have an exciting event coming up this weekend and I thought of you. Do you have a minute?`,
  feedback: `Hi ${name}! This is Priya from the venue. You visited us recently and we'd love your quick feedback. Do you have 2 minutes?`,
  offer: `Hello ${name}! This is Priya from the venue. We have an exclusive offer just for our valued customers. Can I share the details?`
};

const greeting = templates[purpose] || templates.follow_up;

const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Aditi" language="en-IN">${greeting}</Say>
  <Record maxLength="15" timeout="3" playBeep="false" transcribe="false"
    action="${base}/webhook/voice-agent/turn?sid=${sid}" />
  <Say voice="Polly.Aditi" language="en-IN">Hello? I am here whenever you are ready.</Say>
  <Record maxLength="15" timeout="5" playBeep="false" transcribe="false"
    action="${base}/webhook/voice-agent/turn?sid=${sid}" />
</Response>`;

return [{ json: { twiml_response: twiml, is_voicemail: false } }];

// Filter to last 24 hours only
const cutoff = new Date(Date.now() - 24 * 60 * 60 * 1000);
const items = $input.all().filter(i => {
  try { return new Date(i.json.timestamp) >= cutoff; }
  catch(e) { return false; }
});

if (items.length === 0) {
  return [{ json: { conversations: [], total: 0, skip_analysis: true } }];
}

// Calculate metrics
let intents = {}, langs = {}, emotions = {};
items.forEach(i => {
  const d = i.json;
  intents[d.intent] = (intents[d.intent] || 0) + 1;
  langs[d.language] = (langs[d.language] || 0) + 1;
  emotions[d.emotion] = (emotions[d.emotion] || 0) + 1;
});

const summary = items.map(i => `[${i.json.intent}/${i.json.emotion}] Caller: "${i.json.caller_said}" → Agent: "${i.json.agent_said}"`).join('\n');

return [{ json: {
  conversations: summary,
  total: items.length,
  intent_breakdown: intents,
  language_breakdown: langs,
  emotion_breakdown: emotions,
  skip_analysis: false
}}];

